import{_ as d,o as Z,c as g,a2 as l}from"./chunks/framework.D7toiNRm.js";const e=JSON.parse('{"title":"Architecture Overview","description":"","frontmatter":{"aside":false,"pageClass":"aosc-wide-page"},"headers":[],"relativePath":"concepts/architecture-overview.md","filePath":"concepts/architecture-overview.md","lastUpdated":1781637126000}'),b={name:"concepts/architecture-overview.md"};function i(C,I,t,m,c,a){return Z(),g("div",null,[...I[0]||(I[0]=[l(`<h1 id="architecture-overview" tabindex="-1">Architecture Overview <a class="header-anchor" href="#architecture-overview" aria-label="Permalink to &quot;Architecture Overview&quot;">​</a></h1><p>AOSC separates migration orchestration from shard-local data movement.</p><h2 id="architecture-diagram" tabindex="-1">Architecture Diagram <a class="header-anchor" href="#architecture-diagram" aria-label="Permalink to &quot;Architecture Diagram&quot;">​</a></h2><figure class="drawio-figure drawio-export" data-drawio-xml="" data-drawio-title="aosc-architecture.drawio"><div class="drawio-loading">Rendering diagram...</div><img alt="aosc-architecture.drawio" loading="lazy" hidden><figcaption>aosc-architecture.drawio</figcaption></figure><h2 id="components" tabindex="-1">Components <a class="header-anchor" href="#components" aria-label="Permalink to &quot;Components&quot;">​</a></h2><div class="aosc-table-scroll"><table class="aosc-table"><thead><tr><th>Component</th><th>Role</th></tr></thead><tbody><tr><td>Coordinator</td><td>Runs on the cluster-manager node. Owns coordinator phase transitions and cutover.</td></tr><tr><td>Shard worker</td><td>Runs on a data node that holds a source primary shard. Performs backfill and replay for that shard.</td></tr><tr><td>Backfill permit manager</td><td>Limits how many shard workers per node may do heavy backfill work at once.</td></tr><tr><td>Bulk writer</td><td>Sends transformed index/delete operations to the target.</td></tr><tr><td><code>.aosc-migrations</code></td><td>Stores migration documents and detailed progress snapshots.</td></tr><tr><td>Cluster state</td><td>Carries active coordinator and shard phase state.</td></tr></tbody></table></div><h2 id="data-flow" tabindex="-1">Data Flow <a class="header-anchor" href="#data-flow" aria-label="Permalink to &quot;Data Flow&quot;">​</a></h2><pre class="mermaid">graph LR
    Source[Source index] --&gt;|Backfill docs| Worker[Shard worker]
    Source --&gt;|Operation history| Worker
    Worker --&gt;|Bulk index/delete| Target[Target index]
    Worker --&gt;|Shard progress| State[Cluster state]
    Coord[Coordinator] --&gt;|Phase changes| State
    Coord --&gt;|Alias swap| Alias[Index alias]
</pre><p>Backfill reads source documents, applies the configured transform, and indexes target documents with the same ID and routing when routing is present.</p><p>Replay reads source operation history through OpenSearch shard APIs. Index/create operations are transformed and indexed into the target. Delete operations are applied to the target according to the detected routing mode.</p><h2 id="start-preconditions" tabindex="-1">Start Preconditions <a class="header-anchor" href="#start-preconditions" aria-label="Permalink to &quot;Start Preconditions&quot;">​</a></h2><p>Before accepting a migration, AOSC validates that:</p><ul><li>Source and target indices exist.</li><li>Source and target index names are different.</li><li>The alias is valid for cutover.</li><li>The plugin is installed consistently on all nodes.</li><li>The target routing mode can be handled, or explicit consent has been provided for risky routing cases.</li><li>The transform and validation query are valid enough to start.</li></ul><p>AOSC does not create the target index.</p><h2 id="migration-lifecycle" tabindex="-1">Migration Lifecycle <a class="header-anchor" href="#migration-lifecycle" aria-label="Permalink to &quot;Migration Lifecycle&quot;">​</a></h2><ol><li><code>INITIALIZING</code>: create the migration record and prepare workers.</li><li><code>ACTIVE</code>: workers backfill and replay until converged.</li><li><code>PREPARING_TARGET</code>: restore target settings and wait for readiness.</li><li><code>CUTTING_OVER</code>: apply source write block and flush source.</li><li><code>CATCHING_UP</code>: workers replay final operations.</li><li><code>COMPLETING</code>: validate, swap alias, remove source write block if configured, and clean up.</li><li>Terminal phase: <code>COMPLETED</code>, <code>CANCELLED</code>, or <code>FAILED</code>.</li></ol><h2 id="failure-model" tabindex="-1">Failure Model <a class="header-anchor" href="#failure-model" aria-label="Permalink to &quot;Failure Model&quot;">​</a></h2><p>AOSC prefers failing closed over serving a partial cutover. Before alias swap, failure should leave the alias on the source. If alias swap has already completed, AOSC does not roll the alias back automatically because writes may already be landing on the target.</p><p>Cancellation and failure cleanup release leases and remove the source write block where possible. Target index deletion is manual.</p><h2 id="transform-boundary" tabindex="-1">Transform Boundary <a class="header-anchor" href="#transform-boundary" aria-label="Permalink to &quot;Transform Boundary&quot;">​</a></h2><p>The base plugin supports the OpenSearch <code>update</code> script context. Scripts mutate <code>ctx._source</code>; omit <code>transform_script</code> for identity behavior.</p><p>Built-in transforms are one-source-document to one-target-document. Fan-out, joins, external lookups, and cross-cluster movement are outside the base plugin contract.</p><h2 id="backpressure-boundary" tabindex="-1">Backpressure Boundary <a class="header-anchor" href="#backpressure-boundary" aria-label="Permalink to &quot;Backpressure Boundary&quot;">​</a></h2><p>AOSC limits migration pressure with per-node backfill permits, fixed or adaptive batch sizing, optional adaptive backfill concurrency, and overload backoff after repeated write failures. See <a href="./backpressure-and-throttling">Backpressure and Throttling</a>.</p><p>Do not treat AOSC as zero-interruption or universally safe. It has a source write block during cutover, same-cluster scope, and routing constraints that must be reviewed before changing shard counts.</p><h2 id="data-model" tabindex="-1">Data Model <a class="header-anchor" href="#data-model" aria-label="Permalink to &quot;Data Model&quot;">​</a></h2><div class="aosc-table-scroll"><table class="aosc-table"><thead><tr><th>Class</th><th>Purpose</th></tr></thead><tbody><tr><td><code>MigrationRequest</code></td><td>User-submitted start request.</td></tr><tr><td><code>MigrationRequestOptions</code></td><td>Per-migration overrides.</td></tr><tr><td><code>MigrationDocument</code></td><td>Detailed migration document persisted in <code>.aosc-migrations</code>.</td></tr><tr><td><code>MigrationSummary</code></td><td>Slim list API projection.</td></tr><tr><td><code>ShardProgressDocument</code></td><td>Per-shard phase and per-phase counters.</td></tr><tr><td><code>CoordinatorPhase</code></td><td>Migration-level state enum.</td></tr><tr><td><code>ShardPhase</code></td><td>Worker-level state enum.</td></tr></tbody></table></div>`,27)])])}const G=d(b,[["render",i]]);export{e as __pageData,G as default};
